mapper.update:
update goods
goods_name = #{goodsName}, type_id = #{typeId}, buy_price = #{buyPrice}, sell_price = #{sellPrice}, stock_num = #{stockNum}, image_url = #{imageUrl}, remark = #{remark}, update_time = now()
where id = #{id}

mapper.select:
select g.*, t.type_name from goods g left join goods_type t on g.type_id = t.id
and g.goods_name like concat('%',#{goodsName},'%')
and g.type_id = #{typeId}
